// Existing customer - extract their data with full history
const customerData = $input.first().json.data[0];
const vapiData = $('Vapi Webhook Trigger').first().json;

// Calculate customer value tier
let valueTier = 'STANDARD';
const jobsCount = customerData.jobsCount || 0;
const membershipStatus = customerData.membershipStatus || 'None';

if (membershipStatus !== 'None' || jobsCount >= 5) {
  valueTier = 'VIP';
} else if (jobsCount >= 2) {
  valueTier = 'RETURNING';
}

return {
  json: {
    customerId: customerData.id,
    customerName: customerData.name,
    firstName: customerData.name?.split(' ')[0] || 'there',
    isNewCustomer: false,
    locationId: customerData.locations?.[0]?.id || null,
    address: customerData.locations?.[0]?.address || null,
    valueTier: valueTier,
    customerHistory: {
      totalJobs: jobsCount,
      membershipStatus: membershipStatus,
      lastServiceDate: customerData.lastServiceDate || null,
      totalRevenue: customerData.totalRevenue || 0
    },
    callerPhone: vapiData.message?.call?.customer?.number,
    extractedData: vapiData.extracted_data || {}
  }
};

