    customerName: newCustomer.name,
    firstName: newCustomer.name?.split(' ')[0] || 'there',
    isNewCustomer: true,
    locationId: newCustomer.locations?.[0]?.id || null,
    address: newCustomer.locations?.[0]?.address || null,
    valueTier: 'NEW',
    customerHistory: {
      totalJobs: 0,
      membershipStatus: 'None',
      lastServiceDate: null,
      totalRevenue: 0
    },
    callerPhone: vapiData.message?.call?.customer?.number,
    extractedData: vapiData.extracted_data || {}
  }
};

// Transform ServiceTitan availability to human-readable format
// Optimized for voice AI consumption

const availabilityData = $input.first().json.availability || [];
const customerData = $('Merge Customer Data').first().json;
const maxSlotsToOffer = 3;
const diagnosticFee = parseInt($env.DIAGNOSTIC_FEE) || 89;

function formatTimeSlot(isoString) {
  const date = new Date(isoString);
  const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const dayName = days[date.getDay()];

  let hours = date.getHours();
  const minutes = date.getMinutes();
  const ampm = hours >= 12 ? 'PM' : 'AM';
  hours = hours % 12;
  hours = hours ? hours : 12;

  const timeStr = minutes > 0 ? `${hours}:${minutes.toString().padStart(2, '0')} ${ampm}` : `${hours} ${ampm}`;
  return `${dayName} at ${timeStr}`;
}

function getRelativeDay(isoString) {
  const slotDate = new Date(isoString);
  const today = new Date();
  const tomorrow = new Date(today);
  tomorrow.setDate(tomorrow.getDate() + 1);

  slotDate.setHours(0, 0, 0, 0);
  const todayMidnight = new Date(today);
  todayMidnight.setHours(0, 0, 0, 0);
  const tomorrowMidnight = new Date(tomorrow);
  tomorrowMidnight.setHours(0, 0, 0, 0);

  if (slotDate.getTime() === todayMidnight.getTime()) {
    return 'today';
  } else if (slotDate.getTime() === tomorrowMidnight.getTime()) {
    return 'tomorrow';
  }
  return null;
}

// Flatten all slots and sort by date
const allSlots = [];

for (const day of availabilityData) {
  if (day.slots && Array.isArray(day.slots)) {
    for (const slot of day.slots) {
      allSlots.push({
        start: slot.start,
        end: slot.end,
        technicianId: slot.technicianId || null,
        technicianName: slot.technicianName || null,
        date: day.date,
        arrivalWindowStart: slot.arrivalWindowStart || slot.start,
        arrivalWindowEnd: slot.arrivalWindowEnd || slot.end
      });
    }
  }
}

// Sort by start time
allSlots.sort((a, b) => new Date(a.start) - new Date(b.start));

// Take top slots
const topSlots = allSlots.slice(0, maxSlotsToOffer);

if (topSlots.length === 0) {
  return {
    json: {
      hasAvailability: false,
      speakableSlots: null,
      rawSlots: [],
      customerData: customerData,
      errorMessage: "No diagnostic appointments available in the next 48 hours.",
      fallbackAction: 'CALLBACK_PROMISE'
    }
  };
}

// Build speakable string with natural language
const speakableParts = topSlots.map((slot, index) => {
  const formatted = formatTimeSlot(slot.start);
  const relative = getRelativeDay(slot.start);

  if (relative) {
    const time = formatted.split(' at ')[1];
    return `${relative} at ${time}`;
  }
  return formatted;
});

let speakableString;
if (speakableParts.length === 1) {
  speakableString = `I have an opening ${speakableParts[0]}.`;
} else if (speakableParts.length === 2) {
  speakableString = `I have openings ${speakableParts[0]} or ${speakableParts[1]}.`;
} else {
  const lastSlot = speakableParts.pop();
  speakableString = `I have openings ${speakableParts.join(', ')}, or ${lastSlot}.`;
}

// Customize fee messaging based on customer tier
let feeMessage;
switch (customerData.valueTier) {
  case 'VIP':
    feeMessage = `As a valued customer, the diagnostic fee is just $${diagnosticFee}, and we'll apply that toward any repair.`;
    break;
  case 'RETURNING':
    feeMessage = `The diagnostic fee is $${diagnosticFee}, and that gets our best technician to your door with a fully-stocked truck.`;
    break;
  case 'NEW':
    feeMessage = `The diagnostic fee is $${diagnosticFee}, which ensures a licensed technician arrives ready to diagnose and likely fix the issue on the spot.`;
    break;
  default:
    feeMessage = `The diagnostic fee is $${diagnosticFee}, and that gets a technician to your door with everything needed to fix most issues on the spot.`;
}

speakableString += ` ${feeMessage} Which time works best for you?`;

// Build slot details for booking
const slotsOffered = topSlots.map((s, idx) => ({
  index: idx + 1,
  displayTime: formatTimeSlot(s.start),
  relativeDay: getRelativeDay(s.start),
  isoStart: s.start,
  isoEnd: s.end,
  technicianId: s.technicianId,
  technicianName: s.technicianName,
  arrivalWindow: {
    start: s.arrivalWindowStart,
    end: s.arrivalWindowEnd
  }
}));

return {
  json: {
    hasAvailability: true,
    speakableSlots: speakableString,
    slotsOffered: slotsOffered,
    totalAvailableSlots: allSlots.length,
    allSlots: allSlots,
    customerData: customerData,
    diagnosticFee: diagnosticFee
  }
};

